import{_ as i,W as e,X as a,Z as t}from"./framework-805da640.js";const o={},n=t('<h2 id="字节序" tabindex="-1"><a class="header-anchor" href="#字节序" aria-hidden="true">#</a> 字节序</h2><ul><li><strong>大端法</strong>：高字节存储在低地址，网络传输中采用，又叫网络字节序</li><li><strong>小端法</strong>：高字节存储在高地址，现代PC基本采用，又叫主机字节序</li></ul><p>以<code>0x01234567</code>为例：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230601093023.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>当格式化的数据（比如32 bit整型数和16 bit短整型数）在两台使用不同字节序的主机之间直接传递时，接收端必然错误地解释之。</p><p><strong>解决问题的方法是</strong>：发送端总是把要发送的数据转化成大端字节序数据后再发送，而接收端知道对方传送过来的数据总是采用大端字节序，所以接收端可以根据自身采用的字节序决定是否对接收到的数据进行转换（小端机转换，大端机不转换）。</p><p>需要指出的是，即使是同一台机器上的两个进程（比如一个由C语言编写，另一个由JAVA编写）通信，也要考虑字节序的问题（JAVA虚拟机采用大端字节序）。</p><h2 id="编译过程" tabindex="-1"><a class="header-anchor" href="#编译过程" aria-hidden="true">#</a> 编译过程</h2><blockquote><p>csapp,p41</p></blockquote><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230601111232.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="计算机组成" tabindex="-1"><a class="header-anchor" href="#计算机组成" aria-hidden="true">#</a> 计算机组成</h2><blockquote><p>csapp, p44</p></blockquote><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230601111356.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="内存层次" tabindex="-1"><a class="header-anchor" href="#内存层次" aria-hidden="true">#</a> 内存层次</h2><blockquote><p>csapp, p50</p></blockquote><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230601111539.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><blockquote><p>dive into system, p478 <img src="https://minio.kevin2li.top/image-bed/blog/20230601223856.png" alt="" loading="lazy"></p></blockquote><h2 id="进程上下文切换" tabindex="-1"><a class="header-anchor" href="#进程上下文切换" aria-hidden="true">#</a> 进程上下文切换</h2><blockquote><p>csapp, p53</p></blockquote><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230601111934.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>进程虚拟地址空间</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230601112109.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="数据表示" tabindex="-1"><a class="header-anchor" href="#数据表示" aria-hidden="true">#</a> 数据表示</h2><ul><li>浮点数</li></ul><blockquote><p>csapp, p149 <img src="https://minio.kevin2li.top/image-bed/blog/20230601112530.png" alt="" loading="lazy"></p></blockquote>',25),p=[n];function l(g,r){return e(),a("div",null,p)}const d=i(o,[["render",l],["__file","基础知识.html.vue"]]);export{d as default};
